// src/pages/Dashboard.js
import React, { useEffect, useRef, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { useNavigate } from 'react-router-dom';
import { gsap } from 'gsap';
import { useAuth } from '../hooks/useAuth';
import api from '../services/api';
import {
  FaParking, FaCar, FaCheckCircle,
  FaClock, FaFire, FaChartBar,
} from 'react-icons/fa';

function CountdownTimer({ checkIn, durationHours }) {
  const [remaining, setRemaining] = useState('');

  useEffect(() => {
    const end = new Date(checkIn).getTime() + durationHours * 3600000;
    const tick = () => {
      const diff = end - Date.now();
      if (diff <= 0) { setRemaining('Expired'); return; }
      const h = Math.floor(diff / 3600000);
      const m = Math.floor((diff % 3600000) / 60000);
      const s = Math.floor((diff % 60000) / 1000);
      setRemaining(`${h}h ${m.toString().padStart(2,'0')}m ${s.toString().padStart(2,'0')}s`);
    };
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, [checkIn, durationHours]);

  const isExpiring = remaining !== 'Expired' && remaining.startsWith('0h');

  return (
    <div className={`countdown ${isExpiring ? 'expiring' : ''}`}>
      <FaClock />
      <div className="countdown-text">
        <div className="countdown-value">{remaining || '…'}</div>
        <div className="countdown-label">remaining</div>
      </div>
    </div>
  );
}

function OccupancyHeatmap({ slots }) {
  const hours = Array.from({ length: 24 }, (_, i) => i);
  const heat = hours.map(h => {
    if (h >= 7 && h <= 9)   return 0.9;
    if (h >= 12 && h <= 14) return 0.75;
    if (h >= 17 && h <= 19) return 0.85;
    if (h >= 22 || h <= 5)  return 0.1;
    return 0.3 + Math.random() * 0.2;
  });

  const color = (v) => {
    if (v >= 0.8) return '#ef4444';
    if (v >= 0.6) return '#f59e0b';
    if (v >= 0.3) return '#3b82f6';
    return '#10b981';
  };

  return (
    <div className="heatmap large-heatmap">
      <div className="heat-bars" role="img" aria-label="Hourly demand heatmap">
        {heat.map((v, i) => (
          <div key={i} title={`${i}:00 — ${Math.round(v*100)}% occupancy`} className="heat-bar" style={{ height: `${Math.max(5, v*100)}%`, background: color(v) }} />
        ))}
      </div>
      <div className="heat-legend">
        <span>12am</span><span>6am</span><span>12pm</span><span>6pm</span><span>11pm</span>
      </div>
    </div>
  );
}

export default function Dashboard() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const containerRef = useRef(null);

  const { data: slots = [], isLoading: loadingSlots } = useQuery({
    queryKey: ['slots'],
    queryFn: () => api.get('/slots').then(r => r.data),
    refetchInterval: 15000,
  });

  const { data: bookings = [] } = useQuery({
    queryKey: ['bookings'],
    queryFn: () => api.get('/bookings').then(r => r.data),
    enabled: !!user,
  });

  useEffect(() => {
    if (!containerRef.current) return;
    // animate visible items when slots change
    gsap.fromTo(
      containerRef.current.querySelectorAll('.dash-anim'),
      { y: 18, opacity: 0 },
      { y: 0, opacity: 1, duration: 0.45, stagger: 0.06, ease: 'power3.out' }
    );
  }, [slots.length]);

  const available = slots.filter(s => s.status === 'AVAILABLE').length;
  const occupied  = slots.filter(s => s.status === 'OCCUPIED').length;
  const reserved  = slots.filter(s => s.status === 'RESERVED').length;
  const total     = slots.length || 1;
  const occupancyPct = Math.round((occupied / total) * 100);

  const myActiveBooking = bookings.find(b => b.status === 'ACTIVE' && b.user_id === user?.id);
  const mySlot = myActiveBooking ? slots.find(s => s.id === myActiveBooking.slot_id) : null;

  const STATS = [
    { label:'Available', value: available, icon:<FaCheckCircle/>, color:'#10b981', bg:'rgba(16,185,129,0.12)', cls:'green' },
    { label:'Occupied',  value: occupied,  icon:<FaCar/>,         color:'#ef4444', bg:'rgba(239,68,68,0.12)',  cls:'red' },
    { label:'Reserved',  value: reserved,  icon:<FaParking/>,     color:'#f59e0b', bg:'rgba(245,158,11,0.12)', cls:'yellow' },
    { label:'Total Slots',value: total,    icon:<FaChartBar/>,    color:'#00d2ff', bg:'rgba(0,210,255,0.12)',  cls:'primary' },
  ];

  return (
    <div className="page page-dashboard" ref={containerRef} role="main" aria-label="Dashboard">
      <div className="dashboard-shell">
        <main className="dashboard-main">
          {/* Welcome */}
          <section className="dash-anim welcome">
            <h1 className="page-title">👋 Welcome back, <span className="text-gradient">{user?.name || user?.email?.split('@')[0]}</span></h1>
            <p className="muted">{new Date().toLocaleDateString('en-US', { weekday:'long', year:'numeric', month:'long', day:'numeric' })} · Real-time parking status</p>
          </section>

          {/* Active booking banner */}
          {myActiveBooking && mySlot && (
            <section className="dash-anim card banner glow-primary">
              <div className="banner-inner">
                <div className="banner-left">
                  <div className="banner-icon">🅿️</div>
                  <div>
                    <div className="banner-title">Active Booking — Slot {mySlot.slot_number}</div>
                    <div className="muted small">
                      {myActiveBooking.duration_hours}h · ${Number(myActiveBooking.total_amount||0).toFixed(2)} ·{' '}
                      <span className={`pill ${myActiveBooking.payment_status === 'PAID' ? 'paid' : 'pending'}`}>{myActiveBooking.payment_status}</span>
                    </div>
                  </div>
                </div>
                <CountdownTimer
                  checkIn={myActiveBooking.check_in || myActiveBooking.booked_at}
                  durationHours={myActiveBooking.duration_hours || 1}
                />
              </div>
            </section>
          )}

          {/* Stats */}
          <section className="dash-anim stats-grid">
            {STATS.map(s => (
              <div key={s.label} className={`stat-card ${s.cls}`}>
                <div className="stat-icon" style={{ background: s.bg, color: s.color }}>{s.icon}</div>
                <div className="stat-content">
                  <div className="stat-value" style={{ color: s.color }}>{s.value}</div>
                  <div className="stat-label">{s.label}</div>
                </div>
              </div>
            ))}
          </section>

          {/* Occupancy bar + heatmap */}
          <section className="dash-anim grid-two">
            <div className="card">
              <div className="card-head">
                <h5>🔥 Occupancy Rate</h5>
                <div className={`occupancy-value ${occupancyPct >= 80 ? 'peak' : occupancyPct >= 50 ? 'high' : 'ok'}`}>{occupancyPct}%</div>
              </div>
              <div className="progress-wrap">
                <div className="progress-bar-track">
                  <div className="progress-bar-fill" style={{ width: `${occupancyPct}%` }} />
                </div>
                <div className="muted small space-between">
                  <span>{available} available</span><span>{occupied} occupied</span>
                </div>
              </div>
            </div>

            <div className="card">
              <h5 className="card-title"><FaFire /> Hourly Demand Heatmap</h5>
              <OccupancyHeatmap slots={slots} />
              <div className="heat-keys muted small">
                {[['#10b981','Low'],['#3b82f6','Medium'],['#f59e0b','High'],['#ef4444','Peak']].map(([c,l]) => (
                  <div key={l} className="heat-key"><span className="dot" style={{ background:c }} />{l}</div>
                ))}
              </div>
            </div>
          </section>

          {/* Slot Grid */}
          <section className="dash-anim card parking-shell">
            <div className="parking-head">
              <h4>🅿️ Live Parking Map</h4>
              <button className="btn-suprs" onClick={() => navigate('/booking')}>+ Book a Slot</button>
            </div>

            <div className="parking-grid">
              {loadingSlots && Array.from({ length: 12 }).map((_, i) => (
                <div key={`skeleton-${i}`} className="slot-box skeleton" />
              ))}

              {!loadingSlots && slots.map(slot => {
                const st = (slot.status || 'available').toLowerCase();
                return (
                  <div key={slot.id} className={`slot-box ${st}`} onClick={() => st === 'available' && navigate('/booking')}>
                    <div className="slot-emoji">{st === 'available' ? '🟢' : st === 'occupied' ? '🔴' : '🟡'}</div>
                    <div className="slot-number">{slot.slot_number}</div>
                    <div className={`slot-status-badge ${st}`}>{slot.status}</div>
                    {slot.price_per_hour && <div className="slot-meta">${slot.price_per_hour}/hr</div>}
                    {st === 'occupied' && slot.occupant_email && <div className="slot-meta small muted">{slot.occupant_email.split('@')[0]}</div>}
                  </div>
                );
              })}
            </div>

            {slots.length === 0 && !loadingSlots && (
              <div className="empty-state">No slots configured yet. Ask an admin to add slots.</div>
            )}
          </section>
        </main>

        <aside className="dashboard-side">
          <div className="side-card">
            <h6>Quick Actions</h6>
            <div className="muted small">Manage slots, view reports, or create promotions.</div>
          </div>

          <div className="side-card">
            <h6>Tips</h6>
            <ul className="muted small">
              <li>Keep occupancy under 80% to avoid peak overload.</li>
              <li>Use the heatmap to schedule promotions in low hours.</li>
            </ul>
          </div>
        </aside>
      </div>
    </div>
  );
}